class ParkingSystem {
public:
    ParkingSystem(int big, int medium, int small) {
        parkingSpaces[0] = big;
        parkingSpaces[1] = medium;
        parkingSpaces[2] = small;
    }

    bool addCar(int carType) {
        --carType;
        return parkingSpaces[carType]-- > 0;
    }
private:
    int parkingSpaces[3];
};
```

